output.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?mine ?mineLabel WHERE {
  ?mine wdt:P31 wd:Q441533 ; wdt:P17 wd:Q30 .
  OPTIONAL {
    ?mine rdfs:label ?mineLabel .
    FILTER(lang(?mineLabel) = "en")
  }
}
